diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index c1ce364eb179..5659ef8a8aab 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1783,6 +1783,29 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
     Value *UMax = Builder.CreateBinaryIntrinsic(Intrinsic::umax, A, OneConst);
     return replaceInstUsesWith(I, UMax);
   }
+  // (X >> C) + ((X & Mask) != 0) --> (X + Mask) >> C where Mask = (1 << C) - 1 // TEST
+  // Only valid when the add does not overflow.
+  Value *X;
+  const APInt *ShiftC, *MaskC;
+  if (match(&I, m_c_Add(m_OneUse(m_LShr(m_Value(X), m_APInt(ShiftC))),
+                        m_ZExt(m_SpecificICmp(ICmpInst::ICMP_NE,
+                                              m_And(m_Deferred(X), m_APInt(MaskC)),
+                                              m_ZeroInt()))))) {
+    // Verify MaskC == low C bits set
+    if (MaskC->getBitWidth() == ShiftC->getBitWidth() &&
+        ShiftC->ult(MaskC->getBitWidth()) &&
+        *MaskC == APInt::getLowBitsSet(MaskC->getBitWidth(), ShiftC->getZExtValue())) {
+      // Ensure X + Mask does not overflow.
+      if (willNotOverflowUnsignedAdd(X, ConstantInt::get(I.getType(), *MaskC), I)) {
+        Value *MaskV = ConstantInt::get(I.getType(), *MaskC);
+        Value *Add = Builder.CreateAdd(X, MaskV);
+        return BinaryOperator::CreateLShr(Add, ConstantInt::get(I.getType(), *ShiftC));
+      }
+    }
+  }
+
+
+

   if (Instruction *Ashr = foldAddToAshr(I))
     return Ashr;

